#include <iostream>
using namespace std;

int main() {
    int angle;
    if (!(cin >> angle)) return 0;

    if (angle < 90) {
        cout << "Acute" << endl;
    } else if (angle == 90) {
        cout << "Right" << endl;
    } else if (angle < 180) {
        cout << "Obtuse" << endl;
    } else {
        cout << "Straight" << endl;
    }

    return 0;
}

