#include <iostream>
using namespace std;

int main() {
    int year;
    cin >> year;

    // A year is a leap year if:
    // (divisible by 4 AND NOT divisible by 100) OR (divisible by 400)
    if ((year % 4 == 0 && year % 100 != 0) || (year % 400 == 0)) {
        cout << year << " is a leap year" << endl;
    } else {
        cout << year << " is a common year" << endl;
    }

    return 0;
}

